import React, { useState } from 'react';
import '../assets/styles/Zoom.css';
import SaveIcon from '@mui/icons-material/Save';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import StopIcon from '@mui/icons-material/Stop';
import RefreshIcon from '@mui/icons-material/Refresh';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import NavigateBeforeIcon from '@mui/icons-material/NavigateBefore';
import VolumeUpIcon from '@mui/icons-material/VolumeUp';
import VolumeDownIcon from '@mui/icons-material/VolumeDown';
import CloseIcon from '@mui/icons-material/Close';

const Zoom = () => {
  const [showConfirm, setShowConfirm] = useState(false);

  const handleRequest = (url) => {
    fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      }
    })
    .catch(error => {
      console.error('Error:', error);
    });
  };

  const handleActivateZoom = () => {
    handleRequest('/shortcuts/zoom/activate-zoom/');
  };


  const handleCloseZoom = () => {
    handleRequest('/shortcuts/zoom/close-zoom/');
    setShowConfirm(false);
  };

  const confirmCloseZoom = () => {
    setShowConfirm(true);
  }

  return (
    <div className="zoom-container">
      <h1 className="title">Zoom</h1>
      <div className="button-container">
        <button onClick={handleActivateZoom} className="button activate-zoom-button">
          <RefreshIcon className="button-icon" /> Adu în față Zoom
        </button>
        
        <button onClick={handleIncreaseVolume} className="button increase-volume-button">
          <VolumeUpIcon className="button-icon" />
        </button>
        <button onClick={handleDecreaseVolume} className="button decrease-volume-button">
          <VolumeDownIcon className="button-icon" />
        </button>
        <button onClick={confirmCloseZoom} className="button close-zoom-button">
          <CloseIcon className="button-icon" /> Închide Zoom
        </button>
      </div>
      {showConfirm && (
        <div className="modal">
          <div className="modal-content">
            <p>Ești sigur că vrei să închizi Zoom?</p>
            <button onClick={handleCloseZoom} className="confirm-button">Da</button>
            <button onClick={() => setShowConfirm(false)} className="cancel-button">Nu</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Zoom;
